<?php include '_header.php'; if($_SERVER['REQUEST_METHOD']==='POST'){csrf_verify(); if(isset($_POST['delete'])){db()->prepare('DELETE FROM products WHERE id=?')->execute([$_POST['delete']]);} else {$img=upload_image('image',$_POST['old_image']?:null); $slug=strtolower(trim(preg_replace('/[^a-z0-9]+/','-',$_POST['name']),'-')); $data=[$_POST['category_id']?:null,$_POST['name'],$slug,$_POST['description'],$_POST['price'],$_POST['stock'],$img,isset($_POST['is_active'])?1:0]; if($_POST['id']){db()->prepare('UPDATE products SET category_id=?,name=?,slug=?,description=?,price=?,stock=?,image=?,is_active=? WHERE id=?')->execute([...$data,$_POST['id']]);}else{db()->prepare('INSERT INTO products(category_id,name,slug,description,price,stock,image,is_active) VALUES(?,?,?,?,?,?,?,?)')->execute($data);}} redirect('products.php');} $cats=db()->query('SELECT * FROM categories')->fetchAll(); $edit=null; if(isset($_GET['edit'])){$q=db()->prepare('SELECT * FROM products WHERE id=?');$q->execute([(int)$_GET['edit']]);$edit=$q->fetch();} $rows=db()->query('SELECT p.*,c.name cat FROM products p LEFT JOIN categories c ON c.id=p.category_id ORDER BY p.id DESC')->fetchAll(); ?>
<h1>CRUD Produk</h1><form method="post" enctype="multipart/form-data" class="premium-card p-3 row g-2 mb-4"><input type="hidden" name="_csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=e($edit['id']??'')?>"><input type="hidden" name="old_image" value="<?=e($edit['image']??'')?>"><div class="col-md-3"><input class="form-control" name="name" placeholder="Nama" value="<?=e($edit['name']??'')?>" required></div><div class="col-md-2"><select class="form-select" name="category_id"><option value="">Kategori</option><?php foreach($cats as $c):?><option value="<?=$c['id']?>"><?=e($c['name'])?></option><?php endforeach;?></select></div><div class="col-md-2"><input class="form-control" name="price" type="number" placeholder="Harga" value="<?=e($edit['price']??'')?>" required></div><div class="col-md-1"><input class="form-control" name="stock" type="number" placeholder="Stok" value="<?=e($edit['stock']??'10')?>"></div><div class="col-md-4"><input class="form-control" name="image" type="file" accept="image/*"></div><div class="col-12"><textarea class="form-control" name="description" placeholder="Deskripsi"><?=e($edit['description']??'')?></textarea></div><label><input type="checkbox" name="is_active" checked> Aktif</label><div><button class="btn btn-light">Simpan Produk</button><?php if($edit): ?> <a class="btn btn-outline-light" href="products.php">Batal Edit</a><?php endif; ?></div></form><table class="table table-dark"><tr><th>Produk</th><th>Kategori</th><th>Harga</th><th>Stok</th><th></th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['name'])?></td><td><?=e($r['cat'])?></td><td><?=money($r['price'])?></td><td><?=$r['stock']?></td><td><a class="btn btn-sm btn-warning" href="products.php?edit=<?=$r['id']?>">Edit</a> <form class="d-inline" method="post"><input type="hidden" name="_csrf" value="<?=csrf_token()?>"><button class="btn btn-sm btn-danger" name="delete" value="<?=$r['id']?>">Hapus</button></form></td></tr><?php endforeach;?></table><?php include '_footer.php'; ?>
